#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum AppIcon {
    Favorite,
    FavoriteFilled,
    Pin,
    PinFilled,
    Text,
    Topmost,
    File,
    Image,
    Delete,
    Clear,
    Settings,
    Github,
    CheckUpdate,
    Pause,
    Play,
}

impl AppIcon {
    fn path(self) -> &'static str {
        match self {
            Self::Favorite => FAVORITE_PATH,
            Self::FavoriteFilled => FAVORITE_FILLED_PATH,
            Self::Pin => PIN_PATH,
            Self::PinFilled => PIN_FILLED_PATH,
            Self::Text => TEXT_PATH,
            Self::Topmost => TOPMOST_PATH,
            Self::File => FILE_PATH,
            Self::Image => IMAGE_PATH,
            Self::Delete => DELETE_PATH,
            Self::Clear => CLEAR_PATH,
            Self::Settings => SETTINGS_PATH,
            Self::Github => GITHUB_PATH,
            Self::CheckUpdate => CHECK_UPDATE_PATH,
            Self::Pause => PAUSE_PATH,
            Self::Play => PLAY_PATH,
        }
    }
}

#[component]
pub fn Icon(icon: AppIcon) -> Element {
    let path = icon.path();

    rsx! {
        svg {
            class: "app-icon",
            view_box: "0 0 1024 1024",
            path {
                d: "{path}",
                fill: "currentColor",
            }
        }
    }
}
